def find_content_children(g, s):
    g.sort()
    s.sort()
    i = j = 0
    res = 0
    while i < len(g) and j < len(s):
        if s[j] >= g[i]:
            res += 1
            i += 1
            j += 1
        else:
            j += 1
    return res

